{"method_body":"{
  var maxIdx := 0;
  var i := 1;
  while i < |inputs|
    invariant 1 <= i <= |inputs|
    invariant 0 <= maxIdx < i
    invariant forall j :: 0 <= j < i ==> inputs[maxIdx] >= inputs[j]
    decreases |inputs| - i
  {
    if inputs[i] > inputs[maxIdx] {
      maxIdx := i;
    }
    i := i + 1;
  }
  hottest := maxIdx + 1;
}"}
